// And groups predicates with the AND operator between them.
func And(predicates ...predicate.UxExecutionPlan) predicate.UxExecutionPlan {
	return predicate.UxExecutionPlan(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.UxExecutionPlan) predicate.UxExecutionPlan {
	return predicate.UxExecutionPlan(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.UxExecutionPlan) predicate.UxExecutionPlan {
	return predicate.UxExecutionPlan(sql.NotPredicates(p))
}
